import { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import api from '../api/api'; // Assuming you have set up Axios or an API instance.

function Category() {
    const { categoryId } = useParams();  // Get categoryId from URL params
    const [posts, setPosts] = useState([]);  // State to hold the posts for this category
    const [loading, setLoading] = useState(true);  // State to track loading status
    const [categoryName, setCategoryName] = useState('');  // State to hold category name
    const [error, setError] = useState(null);  // State to handle errors
    const [categories, setCategories] = useState([]);  // Categories state (optional, in case you need to use them)

    useEffect(() => {
        const fetchCategoryData = async () => {
            try {
                // Fetch the category name using categoryId
                const categoryResponse = await api.get(`/categories/${categoryId}`);
                setCategoryName(categoryResponse.data.name);

                // Fetch posts in this category
                const postsResponse = await api.get(`/posts?categories=${categoryId}&_embed`);
                setPosts(postsResponse.data);  // Set the posts data to state
            } catch (err) {
                setError('Failed to fetch posts for this category');
                console.error('Error fetching category posts:', err);
            } finally {
                setLoading(false);  // Set loading to false once the request is completed
            }
        };

        fetchCategoryData();
    }, [categoryId]);  // The effect will run when categoryId changes

    if (loading) {
        return <div>Loading...</div>;  // Show loading indicator while fetching data
    }

    if (error) {
        return <div>{error}</div>;  // Show error message if something goes wrong
    }

    return (
        <div className="container category-page">
            <h1>Posts in Category: {categoryName}</h1>

            {posts.length > 0 ? (
                <div className="row">
                    {posts.map((post) => {
                        const image = post._embedded?.['wp:featuredmedia']?.[0]?.source_url;
                        return (
                            <div className="col-lg-4 p-3 m-2 card" key={post.id}>
                                {image && <img src={image} alt={post.title.rendered} className="card-img-top" />}
                                <div className="card-body">
                                    <h5 className="card-title">{post.title.rendered}</h5>
                                    <p className="card-text" dangerouslySetInnerHTML={{ __html: post.excerpt.rendered }} />
                                    <Link to={`/post/${post.id}`} className="btn btn-primary">Read More</Link>
                                </div>
                            </div>
                        );
                    })}
                </div>
            ) : (
                <p>No posts available for this category.</p>
            )}
        </div>
    );
}

export default Category;
